   151→      videoUrls[question_index] = video_url;
   152→    }
   153→
   154→    // Update responses - use updated_at if column exists, fallback gracefully
   155→    try {
   156→      await pool.query(
   157→        `UPDATE interviews SET responses = $1, video_urls = $2, updated_at = NOW()
   158→         WHERE id = $3`,
