   547→// Submit practice response and get AI coaching
   548→router.post('/practice/submit', authMiddleware, async (req, res) => {
   549→  try {
   550→    const { question_id, category, response_text } = req.body;
   551→    // Default question text from library if not provided
   552→    const libraryQ = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   553→    const question = req.body.question || (libraryQ && libraryQ.question) || `Practice question ${question_id || 'unknown'}`;
   554→
   555→    if (!response_text || response_text.trim().length < 50) {
   556→      return res.status(400).json({ error: 'Response must be at least 50 characters' });
   557→    }
   558→
   559→    // Look up key_points from question library
   560→    const libraryQuestion = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   561→    const keyPoints = libraryQuestion ? libraryQuestion.key_points : ['Content quality', 'Structure', 'Clarity', 'Relevance'];
   562→
   563→    // First, analyze the response with real key points
   564→    const analysis = await analyzeInterviewResponse(
   565→      question,
   566→      response_text,
   567→      keyPoints,
   568→      { subscriptionId: req.user.stripe_subscription_id }
   569→    );
   570→
   571→    // Then, generate detailed coaching
   572→    const coaching = await generateInterviewCoaching(
   573→      question,
   574→      response_text,
   575→      analysis,
   576→      { subscriptionId: req.user.stripe_subscription_id }
   577→    );
   578→
   579→    // Combine analysis and coaching
   580→    const fullCoaching = {
   581→      score: analysis.score,
   582→      strengths: analysis.strengths,
   583→      improvements: analysis.improvements,
   584→      ...coaching
   585→    };
   586→
   587→    // Save practice session
   588→    await pool.query(
