   673→// Get practice statistics
   674→router.get('/practice/stats', authMiddleware, async (req, res) => {
   675→  try {
   676→    const stats = await pool.query(
   677→      `SELECT
   678→        COUNT(*) as total_questions,
   679→        AVG(score) as average_score,
   680→        MAX(created_at) as last_practice
   681→       FROM practice_sessions
   682→       WHERE user_id = $1`,
   683→      [req.user.id]
   684→    );
   685→
   686→    // Calculate improvement (compare first half vs second half of sessions)
   687→    const improvement = await pool.query(
   688→      `WITH ordered_sessions AS (
   689→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   690→               COUNT(*) OVER () as total
   691→        FROM practice_sessions
   692→        WHERE user_id = $1
   693→      )
   694→      SELECT
   695→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   696→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   697→      FROM ordered_sessions`,
   698→      [req.user.id]
   699→    );
   700→
   701→    let improvementPercent = null;
   702→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   703→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   704→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   705→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   706→    }
   707→
   708→    // Calculate day streak
   709→    const streakResult = await pool.query(
   710→      `WITH RECURSIVE date_series AS (
   711→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   712→        UNION ALL
   713→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   714→        FROM date_series
   715→        WHERE days_back < 30
   716→      )
   717→      SELECT COUNT(*) as streak
   718→      FROM date_series d
   719→      WHERE EXISTS (
   720→        SELECT 1 FROM practice_sessions
   721→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   722→      )
   723→      AND d.check_date <= CURRENT_DATE
   724→      AND NOT EXISTS (
   725→        SELECT 1 FROM date_series d2
   726→        WHERE d2.check_date > d.check_date
   727→        AND d2.check_date <= CURRENT_DATE
   728→        AND NOT EXISTS (
   729→          SELECT 1 FROM practice_sessions
   730→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   731→        )
   732→      )`,
   733→      [req.user.id]
   734→    );
   735→
   736→    res.json({
   737→      success: true,
   738→      stats: {
   739→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   740→        average_score: parseFloat(stats.rows[0].average_score) || null,
   741→        improvement: improvementPercent,
   742→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   743→        last_practice: stats.rows[0].last_practice
   744→      }
   745→    });
   746→  } catch (err) {
   747→    console.error('Get practice stats error:', err);
   748→    res.status(500).json({ error: 'Failed to fetch statistics' });
   749→  }
   750→});
