  1023→// Start a mock interview session — generates or pulls questions for the role
  1024→router.post('/mock/start', authMiddleware, async (req, res) => {
  1025→  try {
  1026→    const { target_role, job_description } = req.body;
  1027→
  1028→    if (!target_role || target_role.trim().length < 2) {
  1029→      return res.status(400).json({ error: 'Please enter a target role (e.g., "Software Engineer", "Product Manager")' });
  1030→    }
  1031→
  1032→    const role = target_role.trim();
  1033→    const jdHash = hashJD(job_description);
  1034→
  1035→    // Check if we already have questions in the bank for this role/JD combo
  1036→    let bankQuestions;
  1037→    let usedFallback = false;
  1038→    const existing = await pool.query(
  1039→      `SELECT * FROM question_bank WHERE LOWER(role) = LOWER($1) ${jdHash ? 'AND jd_hash = $2' : 'AND jd_hash IS NULL'}
  1040→       ORDER BY RANDOM()`,
  1041→      jdHash ? [role, jdHash] : [role]
  1042→    );
  1043→
  1044→    if (existing.rows.length >= 8) {
  1045→      // Use existing bank — pick random 8-10
  1046→      bankQuestions = existing.rows.slice(0, Math.min(10, existing.rows.length));
  1047→      console.log(`[mock] Found ${existing.rows.length} existing questions for "${role}", using ${bankQuestions.length}`);
  1048→    } else {
  1049→      // Try to generate new question bank
  1050→      console.log(`[mock] Generating new question bank for "${role}"...`);
  1051→      try {
  1052→        const generated = await generateQuestionBank(role, job_description, {
  1053→          subscriptionId: req.user.stripe_subscription_id
  1054→        });
  1055→
  1056→        if (generated && Array.isArray(generated) && generated.length > 0) {
  1057→          // Store in question_bank
  1058→          const insertedIds = [];
  1059→          for (const q of generated) {
  1060→            try {
  1061→              const result = await pool.query(
  1062→                `INSERT INTO question_bank (role, jd_hash, skills, question_text, question_type, difficulty, key_points)
  1063→                 VALUES ($1, $2, $3, $4, $5, $6, $7)
  1064→                 RETURNING id`,
  1065→                [
  1066→                  role,
  1067→                  jdHash,
  1068→                  q.skills_tested || [],
  1069→                  q.question_text,
  1070→                  q.question_type || 'behavioral',
  1071→                  q.difficulty || 'medium',
  1072→                  q.key_points || []
  1073→                ]
  1074→              );
  1075→              insertedIds.push(result.rows[0].id);
  1076→            } catch (insertErr) {
  1077→              console.error('[mock] Failed to insert question:', insertErr.message);
  1078→            }
  1079→          }
  1080→
  1081→          console.log(`[mock] Stored ${insertedIds.length} questions in bank`);
  1082→
  1083→          // Pull 8-10 random from what we just inserted
  1084→          const freshQuestions = await pool.query(
  1085→            `SELECT * FROM question_bank WHERE id = ANY($1) ORDER BY RANDOM() LIMIT 10`,
  1086→            [insertedIds]
  1087→          );
  1088→          bankQuestions = freshQuestions.rows;
  1089→        }
  1090→      } catch (genErr) {
  1091→        console.warn(`[mock] AI question generation failed (${genErr.message}), using fallback questions`);
  1092→      }
  1093→
  1094→      // FALLBACK: If AI generation failed or returned nothing, insert generic role-adapted questions
  1095→      if (!bankQuestions || bankQuestions.length === 0) {
  1096→        console.log(`[mock] Using fallback questions for "${role}"`);
  1097→        usedFallback = true;
  1098→        const fallbacks = getFallbackMockQuestions(role);
  1099→        const insertedIds = [];
  1100→        for (const q of fallbacks) {
  1101→          try {
  1102→            const result = await pool.query(
  1103→              `INSERT INTO question_bank (role, jd_hash, skills, question_text, question_type, difficulty, key_points)
  1104→               VALUES ($1, $2, $3, $4, $5, $6, $7)
  1105→               RETURNING id`,
  1106→              [role, jdHash, q.skills_tested || [], q.question_text, q.question_type, q.difficulty, q.key_points || []]
  1107→            );
  1108→            insertedIds.push(result.rows[0].id);
  1109→          } catch (insertErr) {
  1110→            console.error('[mock] Failed to insert fallback question:', insertErr.message);
  1111→          }
  1112→        }
  1113→        if (insertedIds.length > 0) {
  1114→          const freshQuestions = await pool.query(
  1115→            `SELECT * FROM question_bank WHERE id = ANY($1) ORDER BY RANDOM() LIMIT 10`,
  1116→            [insertedIds]
  1117→          );
  1118→          bankQuestions = freshQuestions.rows;
  1119→        }
  1120→      }
  1121→    }
  1122→
