  1602→    const { uploadFrameToR2 } = require('../lib/polsia-ai');
  1603→    const frameUrl = await uploadFrameToR2(frame, 0);
  1604→    if (!frameUrl) {
  1605→      return res.json({ success: false, error: 'Frame upload failed' });
  1606→    }
  1607→
  1608→    // Quick analysis with vision API — uses provider fallback (GPT-4o → NIM Cosmos → NIM Nemotron VL)
  1609→    const { aiProvider } = require('../lib/polsia-ai');
  1610→    const analysisPrompt = `Quick interview body language check. Rate each as "good", "fair", or "poor" with a 2-3 word tip. Return JSON only:
  1611→{"eye_contact":"good|fair|poor","posture":"good|fair|poor","confidence":"good|fair|poor","expression":"good|fair|poor","tip":"brief tip"}`;
  1612→
  1613→    const text = await aiProvider.visionAnalysis([frameUrl], analysisPrompt, {
  1614→      maxTokens: 200,
  1615→      task: 'interview-realtime-body-language',
  1616→    });
  1617→    let indicators;
  1618→    try {
  1619→      const jsonMatch = text.match(/\{[\s\S]*\}/);
  1620→      indicators = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
  1621→    } catch {
  1622→      indicators = null;
  1623→    }
  1624→
  1625→    if (indicators) {
  1626→      res.json({ success: true, indicators });
